import { d3_pie } from "../../../core/d3-constants";
import { Registry } from "../../../core/zc-registry";

export function getPieLayout(spec){

    
    let { config, data } = spec;

    if(!data){
        data = this.data[0].data[0]; //3d array data
    }

    let columnInfo = this.getColumnByColumnName(spec.column),
        { dataindex } =  columnInfo

    let pie = d3_pie();

    pie.startAngle(config.startAngle)
        .endAngle(config.endAngle)
        .value(d => d[dataindex]);

    return pie(data);
}

Registry.setComponent("pie_layout", getPieLayout);